import type { FilterFn } from '@tanstack/react-table'

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:8000'

// Define the player type
type Player = {
  player_id: string
  name: string
  gamename: string
  country: string
  is_active: boolean
  current_team: string
  puuid_count: number
  region: string
}

// Define sync log entry type
type SyncLogEntry = {
  playerId: string
  playerName: string
  status: 'success' | 'failed'
  message: string
  timestamp: Date
  response?: any
}

export const Route = createFileRoute('/players/')({
  component: RouteComponent,
})

function RouteComponent() {
  const queryClient = useQueryClient()

  // Fetch player data using TanStack Query
  const { data: playersData, isLoading, error } = useQuery<Player[]>({
    queryKey: ['players'],
    queryFn: async () => {
      const response = await fetch(`${API_BASE_URL}/players/data`)
      if (!response.ok) {
        throw new Error('Failed to fetch players')
      }
      const result = await response.json()
      return result.data
    },
  })

  // State for filters
  const [activeFilter, setActiveFilter] = useState<string>('all')
  const [countryFilter, setCountryFilter] = useState<string>('all-countries')
  const [teamFilter, setTeamFilter] = useState<string>('all')
  const [puuidCountFilter, setPuuidCountFilter] = useState<string>('all-counts')
  const [regionFilter, setRegionFilter] = useState<string>('all-regions')
  const [globalFilter, setGlobalFilter] = useState<string>('')

  // Table state
  const [sorting, setSorting] = useState<SortingState>([])
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([])
  const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({})
  const [rowSelection, setRowSelection] = useState({})

  // Sync state
  const [syncingPlayers, setSyncingPlayers] = useState<Set<string>>(new Set())
  const [syncingPuuidPlayers, setSyncingPuuidPlayers] = useState<Set<string>>(new Set())
  const [bulkSyncProgress, setBulkSyncProgress] = useState<Record<string, { current: number, total: number }>>({})
  const [showBulkProgress, setShowBulkProgress] = useState(false)
  const [syncLogs, setSyncLogs] = useState<SyncLogEntry[]>([])
  const [showLogs, setShowLogs] = useState(false)

  // Memoized unique lists for filters
  const uniqueCountries = useMemo(() => {
    return Array.from(new Set(playersData?.map(p => p.country).filter(Boolean) || []))
      .sort((a, b) => a.localeCompare(b))
  }, [playersData])

  const uniqueTeams = useMemo(() => {
    return Array.from(new Set(playersData?.map(p => p.current_team).filter(t => t && t !== '' && t.toLowerCase() !== 'no team') || []))
      .sort((a, b) => a.localeCompare(b))
  }, [playersData])

  const uniquePuuidCounts = useMemo(() => {
    return Array.from(new Set(playersData?.map(p => p.puuid_count) || []))
      .sort((a, b) => a - b)
  }, [playersData])

  const uniqueRegions = useMemo(() => {
    return Array.from(new Set(playersData?.map(p => p.region).filter(Boolean) || []))
      .sort((a, b) => a.localeCompare(b))
  }, [playersData])

  // Define table columns
  const columns = useMemo<ColumnDef<Player>[]>(() => [
    {
      id: "select",
      header: ({ table }) => (
        <input
          type="checkbox"
          checked={table.getIsAllPageRowsSelected()}
          onChange={table.getToggleAllPageRowsSelectedHandler()}
          className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
        />
      ),
      cell: ({ row }) => (
        <input
          type="checkbox"
          checked={row.getIsSelected()}
          onChange={(value) => row.toggleSelected(!!value.target.checked)}
          className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
        />
      ),
      enableSorting: false,
      enableHiding: false,
    },
    {
      accessorKey: "name",
      header: "Name",
      cell: ({ row }) => (
        <a href={`/players/${row.original.player_id}`} className="font-medium text-primary hover:underline">
          {String(row.getValue("name"))}
        </a>
      ),
    },
    {
      accessorKey: "gamename",
      header: "Game Name",
    },
    {
      accessorKey: "country",
      header: "Country",
    },
    {
      accessorKey: "current_team",
      header: "Current Team",
      cell: ({ row }) => (
        <div className="capitalize">{String(row.getValue("current_team"))}</div>
      ),
      filterFn: (row, _id, value) => {
        const teamName = (row.original.current_team || '').trim()
        const isNoTeam = !teamName || teamName.toLowerCase() === 'no team'

        if (value === 'with-team') return !isNoTeam
        if (value === 'without-team') return isNoTeam
        if (value === 'all') return true

        return teamName === value
      },
    },
    {
      accessorKey: "region",
      header: "Region",
      cell: ({ row }) => (
        <div className="capitalize">{String(row.getValue("region") || '-')}</div>
      ),
      filterFn: (row, _id, value) => {
        const region = (row.original.region || '').trim()
        if (value === 'all-regions') return true
        return region === value
      },
    },
    {
      accessorKey: "puuid_count",
      header: "PUUID Count",
      cell: ({ row }) => (
        <Badge variant={row.original.puuid_count > 0 ? 'default' : 'secondary'}>
          {row.original.puuid_count}
        </Badge>
      ),
      filterFn: (row, id, value) => {
        if (value === 'all-counts') return true
        const rowValue = row.getValue(id) as number
        if (value === 'zero') return rowValue === 0
        if (value === 'non-zero') return rowValue > 0
        return rowValue === parseInt(value, 10)
      },
    },
    {
      accessorKey: "is_active",
      header: "Status",
      cell: ({ row }) => (
        <Badge variant={row.original.is_active ? 'default' : 'secondary'}>
          {row.original.is_active ? 'Active' : 'Inactive'}
        </Badge>
      ),
    },
    {
      accessorKey: "player_id",
      header: "Player ID",
      cell: ({ row }) => (
        <div className="font-mono text-xs">{String(row.getValue("player_id"))}</div>
      ),
    },
    {
      id: "actions",
      header: "Actions",
      cell: ({ row }) => {
        const player = row.original
        return (
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={() => syncPlayerTeam(player.player_id)} disabled={syncingPlayers.has(player.player_id)}>
              {syncingPlayers.has(player.player_id) ? <Spinner className="mr-2 h-4 w-4" /> : null}
              {syncingPlayers.has(player.player_id) ? "Syncing..." : "Sync Team"}
            </Button>
            <Button variant="outline" size="sm" onClick={() => syncPlayerPuuid(player.player_id)} disabled={syncingPuuidPlayers.has(player.player_id)}>
              {syncingPuuidPlayers.has(player.player_id) ? <Spinner className="mr-2 h-4 w-4" /> : null}
              {syncingPuuidPlayers.has(player.player_id) ? "Syncing..." : "Sync PUUID"}
            </Button>
            <Button variant="outline" size="sm" asChild>
              <a href={`/players/${player.player_id}`}>View Details</a>
            </Button>
            <Button variant="outline" size="sm" asChild>
              <a href={`https://www.vlr.gg/player/${player.player_id}`} target="_blank" rel="noopener noreferrer">View on VLR</a>
            </Button>
          </div>
        )
      },
    },
  ], [playersData, syncingPlayers, syncingPuuidPlayers])

  const fuzzyFilter: FilterFn<Player> = (row, columnId, value, addMeta) => {
    const itemRank = rankItem(row.getValue(columnId), value)
    addMeta({ itemRank })
    return itemRank.passed
  }

  // Table instance
  const table = useReactTable({
    data: playersData || [],
    columns,
    state: {
      sorting,
      columnFilters,
      columnVisibility,
      rowSelection,
      globalFilter,
    },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getRowId: (row) => row.player_id,
    filterFns: {
      fuzzy: fuzzyFilter as any,
    },
    initialState: {
      pagination: { pageSize: 300 },
    },
  })

  // Apply filters
  useEffect(() => {
    const newFilters = []
    if (activeFilter !== 'all') newFilters.push({ id: 'is_active', value: activeFilter === 'active' })
    if (countryFilter !== 'all-countries') newFilters.push({ id: 'country', value: countryFilter })
    if (puuidCountFilter !== 'all-counts') newFilters.push({ id: 'puuid_count', value: puuidCountFilter })
    if (teamFilter !== 'all') newFilters.push({ id: 'current_team', value: teamFilter })
    if (regionFilter !== 'all-regions') newFilters.push({ id: 'region', value: regionFilter })
    setColumnFilters(newFilters)
    setRowSelection({}) // Clear selections when filters change
  }, [activeFilter, countryFilter, puuidCountFilter, teamFilter, regionFilter])


  const syncPlayerTeam = async (playerId: string) => {
    setSyncingPlayers(prev => new Set(prev).add(playerId))
    try {
      const response = await fetch(`${API_BASE_URL}/players/playerteam`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ player_id: playerId }),
      })
      const data = await response.json()
      if (!response.ok) throw new Error(data.detail?.message || data.message || 'Failed to sync player team')
      toast.success(`Player team synced!`)
      await queryClient.invalidateQueries({ queryKey: ['players'] })
    } catch (error: any) {
      toast.error(error.message || 'Error syncing')
    } finally {
      setSyncingPlayers(prev => { const n = new Set(prev); n.delete(playerId); return n; })
    }
  }

  const syncPlayerPuuid = async (playerId: string) => {
    setSyncingPuuidPlayers(prev => new Set(prev).add(playerId))
    try {
      const response = await fetch(`${API_BASE_URL}/players/puuidsync`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ player_id: playerId }),
      })
      const data = await response.json()
      if (!response.ok) throw new Error(data.detail?.message || data.message || 'Failed')
      toast.success(`PUUID synced!`)
      setSyncLogs(p => [{ playerId, playerName: data.data?.player_name || playerId, status: 'success', message: 'PUUID synced', timestamp: new Date() }, ...p])
      await queryClient.invalidateQueries({ queryKey: ['players'] })
    } catch (error: any) {
      setSyncLogs(p => [{ playerId, playerName: playerId, status: 'failed', message: error.message, timestamp: new Date() }, ...p])
      toast.error(error.message)
    } finally {
      setSyncingPuuidPlayers(prev => { const n = new Set(prev); n.delete(playerId); return n; })
    }
  }

  const bulkSyncTeam = async () => {
    const selectedIds = Object.keys(rowSelection)
    if (selectedIds.length === 0) return

    setShowBulkProgress(true)
    setBulkSyncProgress(prev => ({ ...prev, team: { current: 0, total: selectedIds.length } }))

    for (let i = 0; i < selectedIds.length; i++) {
      const id = selectedIds[i]
      await syncPlayerTeam(id)
      setBulkSyncProgress(prev => ({
        ...prev,
        team: prev.team ? { ...prev.team, current: i + 1 } : { current: i + 1, total: selectedIds.length }
      }))
    }

    setTimeout(() => {
      setBulkSyncProgress(prev => {
        const next = { ...prev };
        delete next.team;
        return next;
      });
    }, 3000)
  }

  const bulkSyncPuuid = async () => {
    const selectedIds = Object.keys(rowSelection)
    if (selectedIds.length === 0) return

    setShowBulkProgress(true)
    setBulkSyncProgress(prev => ({ ...prev, puuid: { current: 0, total: selectedIds.length } }))

    for (let i = 0; i < selectedIds.length; i++) {
      const id = selectedIds[i]
      await syncPlayerPuuid(id)
      setBulkSyncProgress(prev => ({
        ...prev,
        puuid: prev.puuid ? { ...prev.puuid, current: i + 1 } : { current: i + 1, total: selectedIds.length }
      }))
    }

    setTimeout(() => {
      setBulkSyncProgress(prev => {
        const next = { ...prev };
        delete next.puuid;
        return next;
      });
    }, 3000)
  }

  if (isLoading) return <div className="p-8"><Spinner className="mr-2" /> Loading...</div>
  if (error) return <div className="p-8 text-red-500">Error: {(error as Error).message}</div>

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-extrabold tracking-tight">Players Database</h1>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => setShowLogs(!showLogs)}>
            {showLogs ? 'Hide Logs' : 'View Logs'}
          </Button>
        </div>
      </div>

      {showLogs && syncLogs.length > 0 && (
        <Card className="border-red-100 bg-red-50/20">
          <CardContent className="p-4">
            <Accordion type="single" collapsible defaultValue="logs">
              <AccordionItem value="logs" className="border-none">
                <AccordionContent>
                  <div className="space-y-2 max-h-60 overflow-y-auto mt-2">
                    {syncLogs.map((log, i) => (
                      <div key={i} className={`p-2 rounded text-sm flex justify-between ${log.status === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                        <span>{log.playerName}: {log.message}</span>
                        <span className="opacity-50 tracking-tighter">{log.timestamp.toLocaleTimeString()}</span>
                      </div>
                    ))}
                  </div>
                </AccordionContent>
              </AccordionItem>
            </Accordion>
          </CardContent>
        </Card>
      )}

      {/* BULK ACTIONS & PROGRESS */}
      {Object.keys(rowSelection).length > 0 && (
        <Card className="bg-indigo-50 border-indigo-100 shadow-sm">
          <CardContent className="p-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              <Badge variant="outline" className="bg-indigo-100 text-indigo-800 border-indigo-200">
                {Object.keys(rowSelection).length} Selected
              </Badge>
              <h3 className="text-sm font-semibold text-indigo-900">Batch Processing</h3>
            </div>

            <div className="flex flex-wrap gap-2">
              <Button
