                className="bg-indigo-600 hover:bg-indigo-700 text-white"
                disabled={!!bulkSyncProgress.puuid}
              >
                {bulkSyncProgress.puuid ? <Spinner className="mr-2 h-4 w-4" /> : null}
                {bulkSyncProgress.puuid ? `Syncing PUUIDs (${bulkSyncProgress.puuid.current}/${bulkSyncProgress.puuid.total})` : 'Sync Selected PUUIDs'}
              </Button>
              <Button
