import { Label } from '@/components/ui/label'
import { Checkbox } from '@/components/ui/checkbox'
import { toast } from 'sonner'
import { useState, useEffect } from 'react'

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:8000'

// Define the player type
type Player = {
  player_id: string
  name: string
  gamename: string
  country: string
  is_active: boolean
}

// Define the team type
type Team = {
  team_id: string
  name: string
  tag: string
  vct_team: boolean
  logo_url: string
  country: string
  is_active: boolean
  players: Player[]
}

export const Route = createFileRoute('/teams/$teamId')({
  component: TeamDetailComponent,
})

function TeamDetailComponent() {
  const { teamId } = Route.useParams()
  const queryClient = useQueryClient()

  // Fetch team data using TanStack Query
  const { data, isLoading, error } = useQuery<Team>({
    queryKey: ['team', teamId],
    queryFn: async () => {
      const response = await fetch(`${API_BASE_URL}/teams/data/${teamId}`)
      if (!response.ok) {
        throw new Error('Failed to fetch team')
      }
      const result = await response.json()
      return result.data
    },
  })

  // State for update dialog
  const [open, setOpen] = useState(false)
  const [name, setName] = useState('')
  const [tag, setTag] = useState('')
  const [vctTeam, setVctTeam] = useState(false)
  const [logoUrl, setLogoUrl] = useState('')
  const [country, setCountry] = useState('')
  const [isActive, setIsActive] = useState(true)
  const [loading, setLoading] = useState(false)

  // Update form fields when dialog opens
  useEffect(() => {
    if (open && data) {
      setName(data.name)
      setTag(data.tag)
      setVctTeam(data.vct_team)
      setLogoUrl(data.logo_url)
      setCountry(data.country)
      setIsActive(data.is_active)
    }
  }, [open, data])

  // Mutation for updating team
  const updateMutation = useMutation({
    mutationFn: async (updateData: Partial<Team>) => {
      const response = await fetch(`${API_BASE_URL}/teams/update`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          team_id: teamId,
          ...updateData
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.detail?.message || errorData.message || 'Failed to update team')
      }

      return response.json()
    },
    onSuccess: () => {
      toast.success('Team updated successfully!')
      setOpen(false)
      // Invalidate and refetch the team data
      queryClient.invalidateQueries({ queryKey: ['team', teamId] })
    },
    onError: (error: Error) => {
      toast.error(`Failed to update team: ${error.message}`)
    }
  })

  // Mutation for syncing players
  const syncPlayersMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch(`${API_BASE_URL}/players/teamsync`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          team_id: teamId
        })
      });

