import { createFileRoute } from '@tanstack/react-router'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Spinner } from '@/components/ui/spinner'
import { User, Calendar, Link2, Users, Globe, RefreshCw } from 'lucide-react'
import { toast } from 'sonner'

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:8000'

type PlayerDetails = {
  player: {
    player_id: string
    name: string
    gamename: string
    country: string
    is_active: boolean
    aliases: string[]
    canonical_player_id: string | null
  }
  canonical_player: {
    player_id: string
    name: string
    gamename: string
    country: string
    is_active: boolean
  } | null
  linked_players: {
    player_id: string
    name: string
    gamename: string
    country: string
    is_active: boolean
  }[]
  current_team: {
    team_id: string
    name: string
    tag: string
    logo_url: string
    region: string
    country: string
  } | null
  team_history: {
    team_id: string
    name: string
    tag: string
    logo_url: string
    start_date: string | null
    end_date: string | null
    is_current: boolean
  }[]
  puuids: {
    puuid: string
    is_primary: boolean
    is_active: boolean
    assignment_type: string
    assigned_at: string | null
  }[]
}

export const Route = createFileRoute('/players/$playerid')({
  component: PlayerDetailsComponent,
})

function PlayerDetailsComponent() {
  const { playerid } = Route.useParams()
  const queryClient = useQueryClient()

  const { data, isLoading, error } = useQuery<{ data: PlayerDetails }>({
    queryKey: ['player-details', playerid],
    queryFn: async () => {
      const response = await fetch(`${API_BASE_URL}/players/details/${playerid}`)
      if (!response.ok) {
        throw new Error('Failed to fetch player details')
      }
      return response.json()
    },
  })

  // Mutation for syncing team history
  const syncTeamHistoryMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch(`${API_BASE_URL}/players/sync-team-history`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          player_id: playerid
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail?.message || errorData.message || 'Failed to sync team history');
      }

      return response.json();
    },
    onSuccess: (result) => {
      toast.success(result.message || 'Team history synced successfully!');
      // Invalidate and refetch the player details to update team history
      queryClient.invalidateQueries({ queryKey: ['player-details', playerid] });
    },
    onError: (error: Error) => {
      toast.error(`Failed to sync team history: ${error.message}`);
    }
  });

  if (isLoading) {
    return (
      <div className="p-8 flex items-center justify-center">
        <Spinner className="mr-2" /> Loading player details...
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-8 text-red-500">
        Error: {(error as Error).message}
      </div>
    )
  }

  const details = data?.data
  if (!details) {
    return <div className="p-8">No player data found</div>
  }

  const { player, canonical_player, linked_players, current_team, team_history, puuids } = details

  return (
    <div className="p-6 space-y-6">
