      <Card>
        <CardHeader>
          <div className="flex items-center gap-4">
            <div className="p-3 bg-primary/10 rounded-lg">
              <User className="w-8 h-8 text-primary" />
            </div>
            <div>
              <CardTitle className="text-2xl">{player.name || 'Unnamed Player'}</CardTitle>
              <p className="text-muted-foreground font-mono">{player.gamename || player.player_id}</p>
            </div>
          </div>
        </CardHeader>
        <CardContent>
