            <div className="grid gap-2">
              {linked_players.map((lp) => (
                <div key={lp.player_id} className="flex items-center justify-between bg-white p-3 rounded-lg border">
                  <div>
                    <p className="font-medium">{lp.name || 'Unnamed'}</p>
