                  </div>
                  <Button variant="ghost" size="sm" asChild>
                    <a href={`/players/${lp.player_id}`}>View</a>
                  </Button>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Current Team Card */}
      {current_team && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Globe className="w-5 h-5" />
              Current Team
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-4">
              {current_team.logo_url && (
                <img
                  src={current_team.logo_url}
                  alt={`${current_team.name} logo`}
                  className="h-16 w-16 object-contain"
                />
              )}
              <div className="flex-1">
                <p className="text-xl font-semibold">{current_team.name}</p>
                <p className="text-muted-foreground">[{current_team.tag}]</p>
                <div className="flex gap-4 mt-1 text-sm text-muted-foreground">
                  <span>Region: {current_team.region || 'N/A'}</span>
                  <span>Country: {current_team.country || 'N/A'}</span>
                </div>
              </div>
              <Button variant="outline" asChild>
                <a href={`/teams/${current_team.team_id}`}>View Team</a>
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Team History */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <Calendar className="w-5 h-5" />
              Team History
            </CardTitle>
            <Button
              variant="outline"
              size="sm"
              onClick={() => syncTeamHistoryMutation.mutate()}
              disabled={syncTeamHistoryMutation.isPending}
            >
              {syncTeamHistoryMutation.isPending ? (
                <Spinner className="mr-2 h-4 w-4" />
              ) : (
                <RefreshCw className="mr-2 h-4 w-4" />
              )}
              {syncTeamHistoryMutation.isPending ? 'Syncing...' : 'Sync History'}
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {team_history.length === 0 ? (
            <p className="text-muted-foreground">No team history available</p>
          ) : (
            <div className="space-y-3">
              {team_history.map((th, i) => (
                <div key={`${th.team_id}-${i}`} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                  <div className="flex items-center gap-3">
